VALUES
  ('social-worker-moex-04570', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Reamer依據個人經驗，提出社會工作者解決倫理兩難的步驟，下列步驟何者正確？①釐清倫理的', '["找出所有可能被倫理抉擇影響到的個人、團體與組織", "做抉擇並記錄做抉擇的過程", "審慎檢視贊成或反對每一種行動的理由  ⑤監督、評估與記錄倫理抉擇所帶來的結果  ⑥嘗試 找出各種可採取的行動及參與者，並評估每種行動的利弊 ⑦徵詢同儕以及專家的意見", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04571', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '根據Levy（1984）對於社會工作價值的分類，社會工作的核心價值起源於下列那四個價值類別？①', '["組織與制度價值", "專業的價值", "人群服務的實務價值  ⑤社會工作者的個人價值", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04572', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Reamer（1999）參考Rokeach（1973）認為價值係為一種連續信念的說法，將社會工作價值區分 為終極的、中介的以及工具性的三類，下列那一個敘述屬於工具性價值？', '["每一個人都應該享有基本的尊嚴並免於困苦", "對個人、團體或社會而言，可藉由他人幫助以促其朝向積極方向的改變", "人有掌握自己人生方向的能力", "社會工作者應該為案主保密"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04573', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '根據 Roberts（1991）提出的危機處遇七階段來看，下列何者非社會工作者提供危機處遇時需要的 任務？', '["評量案主的致命風險與安全", "確認案主目前的主要問題是什麼", "做潛意識分析以協助釐清問題", "探索可能的替代方案"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04574', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作者在未徵得案主的同意下，將案家的家庭關係負面私密細節透露給媒體，希望透過發布 新聞、爭取曝光率和社會關注，以獲得同情而捐贈協助其獲得更好的生活品質。請問這是合乎倫 理的決策行動嗎？', '["是，因為「生活品質原則」優先於「隱私守密原則」", "否，因為「最小傷害原則」優先於「生活品質原則」", "是，因為個人的幸福權優先於隱私秘密權", "否，因為防止基本善（basicgoods）的傷害優先於保護個人秘密"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04575', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '精神醫療社會工作早期以病理取向為主，近期轉變為強調優勢取向。請問優勢取向對精神治療與 康復之看法，下列何者正確？', '["精神疾病的治療最重要的是藥物治療，精神病患必須完全遵從醫囑", "精神病患和普通人一樣有正常的需求、能力和潛能", "專業人員在精神疾病的治療和康復中是具有權威和力量，只有專業人員才真正了解精神病患的 需要", "社區民眾的角色不重要，因為只有當精神病患不斷服藥和接受訓練時，才能回歸社區"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04576', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作專業服務過程中，社會工作師必須遵守專業規範和倫理守則，否則可能涉及業務過失。 社會工作師一旦涉及業務過失，那一項是與中華民國刑法無關？', '["妨害秘密", "過失傷害罪", "誹謗罪", "損害賠償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04577', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Mary Richmond 與Jane Adams 是社會工作先驅，兩人對社會工作發展各有貢獻，下列關於兩人 之敘述，何者錯誤？', '["Richmond是當代個案工作創始者，奠定個案工作基礎方法", "JaneAdams成立HullHouse關心公民與社會生活，培養許多著名社會工作者", "JaneAdams涉入多項社會改革，如促成白宮兒童會議、建立第一個少年法庭、成立移民保護聯 盟，曾獲頒諾貝爾和平獎，為社會工作界第一人", "Richmond 認為個案工作與社會行動是不同方法，社會行動者不需要個案工作基礎"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04578', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關懷倫理（ethicsofcare）關注被歧視或社會排除弱勢者的感受與需求，強調社會工作者提供服務 應以那一個原則為優先考量？', '["道德原則優先", "行為結果的良善", "對服務對象的責任，而非職責", "服務提供者的正直品格"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04579', 'social-worker', 'social-worker-moex-109-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何者不是在倫理抉擇時，應有的行動？', '["指認可能受倫理決策影響的個人、團體和組織", "辨識各種倫理決策的潛在利益和危險", "只尋找有利於組織立場的辯護資訊", "指認倫理情境中的各種價值、職責與倫理爭議問題"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "68ae45ac430c", "answer_pdf_sha1": "e5cde772083b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
